const HASH_TABLE_SIZE = 10;

function hashFunction(key) {
    return key % HASH_TABLE_SIZE;
}

class HashTable {
    constructor() {
        this.table = Array(HASH_TABLE_SIZE);
    }

    insert(key, value) {
        const index = hashFunction(key);
        this.table[index] = value;
    }

    search(key) {
        const index = hashFunction(key);
        return this.table[index];
    }
}

